// GET /authorize - Authorization endpoint (renders a simple login form)
app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;

  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type', error_description: 'Only "code" response type is supported.' });
  }

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client', error_description: 'Unknown client_id.' });
  }

  if (redirect_uri && !client.redirectUris.includes(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri.' });
  }

  // Render a simple HTML login form
  res.send(`
    <!DOCTYPE html>
    <html>
    <head><title>Authorize - ${client.name}</title></head>
    <body>
      <h2>Sign in to authorize "${client.name}"</h2>
      <p>Requested scope: ${scope || 'default'}</p>
      <form method="POST" action="/authorize">
        <input type="hidden" name="response_type" value="${response_type}" />
        <input type="hidden" name="client_id" value="${client_id}" />
        <input type="hidden" name="redirect_uri" value="${redirect_uri || client.redirectUris[0]}" />
        <input type="hidden" name="scope" value="${scope || ''}" />
        <input type="hidden" name="state" value="${state || ''}" />
        <label>Username: <input type="text" name="username" required /></label><br/><br/>
        <label>Password: <input type="password" name="password" required /></label><br/><br/>
        <button type="submit">Authorize</button>
      </form>
    </body>
    </html>
  `);
});

// POST /authorize - Process authorization (login + consent)
app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password } = req.body;

  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type' });
  }

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  const effectiveRedirectUri = redirect_uri || client.redirectUris[0];
  if (!client.redirectUris.includes(effectiveRedirectUri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri.' });
  }

  const user = await authenticateUser(username, password);
  if (!user) {
    return res.status(401).send(`
      <!DOCTYPE html>
      <html>
      <body>
        <h2>Invalid credentials. <a href="/authorize?response_type=${response_type}&client_id=${client_id}&redirect_uri=${encodeURIComponent(effectiveRedirectUri)}&scope=${scope || ''}&state=${state || ''}">Try again</a></h2>
      </body>
      </html>
    `);
  }

  const code = generateAuthorizationCode();
  await storeAuthorizationCode(code, {
    clientId: client_id,
    userId: user.id,
    username: user.username,
    redirectUri: effectiveRedirectUri,
    scope: scope || '',
    createdAt: Date.now(),
  });

  const redirectUrl = new URL(effectiveRedirectUri);
  redirectUrl.searchParams.set('code', code);
  if (state) {
    redirectUrl.searchParams.set('state', state);
  }

  res.redirect(redirectUrl.toString());
});

// POST /token - Token endpoint
app.post('/token', async (req, res) => {
  const { grant_type } = req.body;

  // Extract client credentials from Authorization header or body
  let clientId, clientSecret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    clientId = decodeURIComponent(parts[0]);
    clientSecret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = authenticateClient(clientId, clientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed.' });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client);
  } else {
    return res.status(400).json({ error: 'unsupported_grant_type', error_description: `Grant type "${grant_type}" is not supported.` });
  }
});

async function handleAuthorizationCodeGrant(req, res, client) {
  const { code, redirect_uri } = req.body;

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing authorization code.' });
  }

  const authCode = await getAndDeleteAuthorizationCode(code);
  if (!authCode) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code is invalid or expired.' });
  }

  if (authCode.clientId !== client.clientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was not issued to this client.' });
  }

  if (redirect_uri && authCode.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch.' });
  }

  const accessTokenPayload = {
    sub: authCode.userId,
    username: authCode.username,
    client_id: client.clientId,
    scope: authCode.scope,
    token_type: 'access_token',
    jti: uuidv4(),
  };

  const accessToken = generateAccessToken(accessTokenPayload);
  const refreshToken = generateRefreshToken();

  const refreshTokenData = {
    token: refreshToken,
    userId: authCode.userId,
    username: authCode.username,
    clientId: client.clientId,
    scope: authCode.scope,
    createdAt: Date.now(),
    expiresAt: Date.now() + REFRESH_TOKEN_EXPIRY_SECONDS * 1000,
    // NOTE: No rotation - the same refresh token is reused each time.
    // This is intentional per requirements but is a security risk.
    useCount: 0,
  };

  await storeRefreshToken(refreshToken, refreshTokenData);
  await storeUserRefreshTokenIndex(authCode.userId, refreshToken);

  console.log(`[TOKEN] Issued access + refresh token for user=${authCode.username}, client=${client.clientId}`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900, // 15 minutes in seconds
    refresh_token: refreshToken,
    scope: authCode.scope,
  });
}

async function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing refresh_token.' });
  }

  const tokenData = await getRefreshToken(refresh_token);
  if (!tokenData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token is invalid or expired.' });
  }

  if (tokenData.clientId !== client.clientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token was not issued to this client.' });
  }

  // Check if token has expired (belt-and-suspenders check; Redis TTL should handle this)
  if (Date.now() > tokenData.expiresAt) {
    await revokeRefreshToken(refresh_token);
    await removeFromUserRefreshTokenIndex(tokenData.userId, refresh_token);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token has expired.' });
  }

  // Determine effective scope
  const effectiveScope = scope || tokenData.scope;

  // If a narrower scope was requested, validate it's a subset
  if (scope) {
    const originalScopes = new Set(tokenData.scope.split(' ').filter(Boolean));
    const requestedScopes = scope.split(' ').filter(Boolean);
    for (const s of requestedScopes) {
      if (!originalScopes.has(s)) {
        return res.status(400).json({ error: 'invalid_scope', error_description: `Scope "${s}" was not in the original grant.` });
      }
    }
  }

  // Issue new access token but REUSE the same refresh token (no rotation)
  const accessTokenPayload = {
    sub: tokenData.userId,
    username: tokenData.username,
    client_id: client.clientId,
    scope: effectiveScope,
    token_type: 'access_token',
    jti: uuidv4(),
  };

  const accessToken = generateAccessToken(accessTokenPayload);

  // Update use count on the refresh token (but don't rotate it)
  tokenData.useCount = (tokenData.useCount || 0) + 1;
  tokenData.lastUsedAt = Date.now();

  // Re-store with remaining TTL (don't extend the TTL on reuse)
  const remainingTTL = Math.floor((tokenData.expiresAt - Date.now()) / 1000);
  if (remainingTTL > 0) {
    const key = `refresh_token:${refresh_token}`;
    await redis.set(key, JSON.stringify(tokenData), 'EX', remainingTTL);
  }

  console.log(`[REFRESH] Reused refresh token (use #${tokenData.useCount}) for user=${tokenData.username}, client=${client.clientId}`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refresh_token, // Same refresh token returned (no rotation)
    scope: effectiveScope,
  });
}

// POST /revoke - Token revocation endpoint (RFC 7009)
app.post('/revoke', async (req, res) => {
  const { token, token_type_hint } = req.body;

  // Authenticate client
  let clientId, clientSecret;
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    clientId = decodeURIComponent(parts[0]);
    clientSecret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = authenticateClient(clientId, clientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing token parameter.' });
  }

  // Try to revoke as refresh token
  const tokenData = await getRefreshToken(token);
  if (tokenData) {
    if (tokenData.clientId !== client.clientId) {
      // Per RFC 7009, respond with 200 even if token doesn't belong to client
      return res.status(200).json({});
    }
    await revokeRefreshToken(token);
    await removeFromUserRefreshTokenIndex(tokenData.userId, token);
    console.log(`[REVOKE] Revoked refresh token for user=${tokenData.username}, client=${client.clientId}`);
  }

  // Always return 200 per RFC 7009
  res.status(200).json({});
});

// GET /userinfo - Protected resource endpoint
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid Authorization header.' });
  }

  const token = authHeader.slice(7);
  const payload = verifyAccessToken(token);
  if (!payload) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token is invalid or expired.' });
  }

  const user = users.get(payload.username);
  if (!user) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'User not found.' });
  }

  res.json({
    sub: user.id,
    username: user.username,
    email: user.email,
  });
});

// GET /admin/tokens/:userId - Admin endpoint to view all refresh tokens for a user
app.get('/admin/tokens/:userId', async (req, res) => {
  const { userId } = req.params;
  const tokens = await getUserRefreshTokens(userId);

  const tokenDetails = [];
  for (const token of tokens) {
    const data = await getRefreshToken(token);
    if (data) {
      tokenDetails.push({
        tokenPrefix: token.substring(0, 12) + '...',
        userId: data.userId,
        username: data.username,
        clientId: data.clientId,
        scope: data.scope,
        createdAt: new Date(data.createdAt).toISOString(),
        expiresAt: new Date(data.expiresAt).toISOString(),
        useCount: data.useCount || 0,
        lastUsedAt: data.lastUsedAt ? new Date(data.lastUsedAt).toISOString() : null,
      });
    } else {
      // Token expired from Redis, clean up index
      await removeFromUserRefreshTokenIndex(userId, token);
    }
  }

  res.json({
    userId,
    activeRefreshTokens: tokenDetails.length,
    tokens: tokenDetails,
  });
});

// POST /admin/revoke-all/:userId - Revoke all refresh tokens for a user
app.post('/admin/revoke-all/:userId', async (req, res) => {
  const { userId } = req.params;
  const tokens = await getUserRefreshTokens(userId);

  let revokedCount = 0;
  for (const token of tokens) {
    await revokeRefreshToken(token);
    await removeFromUserRefreshTokenIndex(userId, token);
    revokedCount++;
  }

  console.log(`[ADMIN] Revoked ${revokedCount} refresh tokens for user=${userId}`);

  res.json({
    userId,
    revokedCount,
  });
});

